import{_ as a,c as i,o as t,aN as n}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"日志管理","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/11-日志管理.md","filePath":"01.Linux基础/11-日志管理.md","lastUpdated":null}'),e={name:"01.Linux基础/11-日志管理.md"};function l(p,s,h,d,o,r){return t(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="日志管理" tabindex="-1">日志管理 <a class="header-anchor" href="#日志管理" aria-label="Permalink to &quot;日志管理&quot;">​</a></h1><p>系统排障主要依赖三类日志来源：systemd journald（服务日志）、rsyslog（传统系统日志）、应用自身写的文件日志。</p><h2 id="一、日志目录和文件" tabindex="-1">一、日志目录和文件 <a class="header-anchor" href="#一、日志目录和文件" aria-label="Permalink to &quot;一、日志目录和文件&quot;">​</a></h2><p>大多数系统和服务的日志集中在 <code>/var/log</code> 下。</p><table tabindex="0"><thead><tr><th>文件</th><th>对应发行版</th><th>内容</th></tr></thead><tbody><tr><td><code>/var/log/messages</code></td><td>RHEL 系</td><td>通用系统日志</td></tr><tr><td><code>/var/log/syslog</code></td><td>Debian/Ubuntu</td><td>通用系统日志</td></tr><tr><td><code>/var/log/secure</code></td><td>RHEL 系</td><td>认证和安全相关日志（SSH 登录、sudo 等）</td></tr><tr><td><code>/var/log/auth.log</code></td><td>Debian/Ubuntu</td><td>认证和安全相关日志</td></tr><tr><td><code>/var/log/dmesg</code></td><td>通用</td><td>内核启动日志的快照</td></tr><tr><td><code>/var/log/cron</code></td><td>部分发行版</td><td>cron 执行日志</td></tr></tbody></table><p>不同的发行版日志文件名不完全相同，排查时先确认目标发行版的命名习惯。遇到登录相关问题看 <code>secure</code> 或 <code>auth.log</code>，内核和硬件问题看 <code>dmesg</code>。</p><h2 id="二、journald-和-journalctl" tabindex="-1">二、journald 和 journalctl <a class="header-anchor" href="#二、journald-和-journalctl" aria-label="Permalink to &quot;二、journald 和 journalctl&quot;">​</a></h2><p>systemd 的日志系统叫 journald。它收拢了 systemd 管理服务的 stdout/stderr、内核日志和部分系统日志，存放在二进制格式的日志文件中（而不是纯文本），查询时使用 <code>journalctl</code>。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 查看全部日志（可能非常多）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 只看指定 unit 的日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 持续跟踪，类似 tail -f</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;1 hour ago&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> err</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 只看 error 级别及以上的日志</span></span></code></pre></div><p>常用参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td><code>-u</code></td><td>过滤指定 systemd unit</td></tr><tr><td><code>-f</code></td><td>持续输出新日志（follow）</td></tr><tr><td><code>--since</code></td><td>起始时间（支持 &quot;today&quot;、&quot;1 hour ago&quot;、&quot;2026-05-21&quot;）</td></tr><tr><td><code>--until</code></td><td>结束时间</td></tr><tr><td><code>-p</code></td><td>按日志级别过滤（emerg、alert、crit、err、warning、notice、info、debug）</td></tr><tr><td><code>-n</code></td><td>显示最近 N 行</td></tr><tr><td><code>--no-pager</code></td><td>不使用分页直接输出，方便脚本处理</td></tr></tbody></table><p>服务启动失败的标准排查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 看状态和最后几行日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 看最近 100 行</span></span></code></pre></div><p>从最近日志开始看，再按时间逐渐扩大范围。一上来就翻全量日志效率很低。</p><p>journald 的持久化行为与 <code>/var/log/journal</code> 目录是否存在有关。如果该目录不存在，journald 默认只在 <code>/run/log/journal</code>（tmpfs，内存中）存储日志，重启后日志丢失。需要持久化时：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/journal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemd-journald</span></span></code></pre></div><h2 id="三、rsyslog" tabindex="-1">三、rsyslog <a class="header-anchor" href="#三、rsyslog" aria-label="Permalink to &quot;三、rsyslog&quot;">​</a></h2><p>rsyslog 是传统的系统日志服务，负责按规则将不同来源的日志写到对应的文本文件中。journald 和 rsyslog 可以同时存在——journald 收集，再通过转发交给 rsyslog 归档。</p><p>主配置和附加配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/rsyslog.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/rsyslog.d/</span></span></code></pre></div><p>重启 rsyslog：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsyslog</span></span></code></pre></div><p>rsyslog 的规则格式是 <code>facility.level 目标</code>：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.info;mail.none;authpriv.none;cron.none    /var/log/messages</span></span>
<span class="line"><span>authpriv.*                                  /var/log/secure</span></span>
<span class="line"><span>cron.*                                      /var/log/cron</span></span></code></pre></div><p>facility 表示日志来源类别（authpriv=认证、cron=定时任务、mail=邮件、daemon=守护进程），level 表示记录的最低等级。<code>authpriv.*</code> 表示认证相关的所有级别的日志都写入 <code>/var/log/secure</code>。</p><p>一般的应用服务不直接修改 rsyslog 配置。只有当需要做集中日志收集、自定义日志路径或调整系统日志行为时才会动它。</p><h2 id="四、dmesg-内核日志" tabindex="-1">四、dmesg 内核日志 <a class="header-anchor" href="#四、dmesg-内核日志" aria-label="Permalink to &quot;四、dmesg 内核日志&quot;">​</a></h2><p><code>dmesg</code> 查看内核环形缓冲区中的消息，包含硬件探测、驱动加载、OOM killer、网络接口状态等信息。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 显示可读时间戳</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50</span></span></code></pre></div><p>过滤异常信息：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;error|fail|oom|reset&quot;</span></span></code></pre></div><p>磁盘 I/O 错误、网卡 link down、OOM 被杀进程、USB 设备异常等都可以在 <code>dmesg</code> 里找到痕迹。需要注意 <code>dmesg -T</code> 显示的时间在某些系统上可能不准——内核的时间戳和系统时间不一定同步，关键事故还是要结合 journald 和其他日志交叉验证。</p><h2 id="五、logrotate-日志轮转" tabindex="-1">五、logrotate 日志轮转 <a class="header-anchor" href="#五、logrotate-日志轮转" aria-label="Permalink to &quot;五、logrotate 日志轮转&quot;">​</a></h2><p>logrotate 解决的是日志文件无限增长的问题。它不减少日志量，只是定期把旧日志改名、压缩、删除。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/logrotate.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 全局配置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/logrotate.d/</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 各服务的独立配置</span></span></code></pre></div><p>一个典型的轮转配置：</p><div class="language-logrotate vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">logrotate</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/log/myapp/*.log {</span></span>
<span class="line"><span>    daily                    # 每天轮转一次</span></span>
<span class="line"><span>    rotate 7                 # 保留最近 7 份</span></span>
<span class="line"><span>    missingok               # 文件不存在不报错</span></span>
<span class="line"><span>    notifempty              # 空文件不轮转</span></span>
<span class="line"><span>    compress                # 压缩旧日志</span></span>
<span class="line"><span>    delaycompress           # 延迟压缩（保留最近一份不压缩，方便仍在查）</span></span>
<span class="line"><span>    copytruncate            # 拷贝后清空原文件</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>copytruncate</code> 的方式：先把日志内容复制到轮转文件，再清空原日志文件。优点是不需要服务支持重新打开日志文件，缺点是复制和清空之间产生的少量日志可能丢失。</p><p>对于支持 reload 信号的服务（如 nginx），更可靠的方式是 <code>postrotate</code>：</p><div class="language-logrotate vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">logrotate</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/log/nginx/*.log {</span></span>
<span class="line"><span>    daily</span></span>
<span class="line"><span>    rotate 14</span></span>
<span class="line"><span>    missingok</span></span>
<span class="line"><span>    notifempty</span></span>
<span class="line"><span>    compress</span></span>
<span class="line"><span>    delaycompress</span></span>
<span class="line"><span>    postrotate</span></span>
<span class="line"><span>        systemctl reload nginx &gt;/dev/null 2&gt;&amp;1 || true</span></span>
<span class="line"><span>    endscript</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>轮转完成后发 reload 信号给服务，让服务重新打开日志文件。这比 <code>copytruncate</code> 更可靠，不会丢日志。</p><p>测试配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">logrotate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/logrotate.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # -d 是 debug 模式，只模拟不执行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">logrotate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/logrotate.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # -f 强制执行一次</span></span></code></pre></div><p>正式强制轮转前先用 <code>-d</code> 模拟跑一遍，特别是带 <code>postrotate</code> 和 <code>--delete</code> 的配置。</p><h2 id="六、日志排查的基本方法" tabindex="-1">六、日志排查的基本方法 <a class="header-anchor" href="#六、日志排查的基本方法" aria-label="Permalink to &quot;六、日志排查的基本方法&quot;">​</a></h2><p>按时间范围定位：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2026-05-21 10:00:00&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --until</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2026-05-21 11:00:00&quot;</span></span></code></pre></div><p>按关键字过滤：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;error&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;error|exception|failed|timeout&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span></code></pre></div><p>关注日志增长速度：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 单个文件大小</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">du</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 各日志目录占用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 观察写入速度</span></span></code></pre></div><p>日志目录单独挂载是一个简单的防护措施。应用程序异常狂写日志时，不至于把根分区打满进而影响整个系统。</p>`,52)])])}const g=a(e,[["render",l]]);export{c as __pageData,g as default};
